package arrays.praticando.aprendendo;import java.util.Arrays;public class ArraysEForEach {    public static void main(String[] args) {        int[] numeros = {1, 2 , 3 , 4 , 5};        String[] nomeNinjas = {"Naruto uzumaki", "Sakura Haruno", "Sasuke Uchiha"};        for (int i = 0; i < numeros.length; i++) {            System.out.println(numeros[i]);        }        for (int c = 0; c < nomeNinjas.length; c++) {            System.out.println(nomeNinjas[c]);        }        for (int i:numeros){            System.out.println(i + " Usando for each");        }    }}